mapper.select:
SELECT e.id, e.expense_type AS expenseType, e.amount, e.expense_date AS expenseDate, e.description, e.receipt_path AS receiptPath, e.registered_by AS registeredBy, emp.name AS registeredByName, e.created_at AS createdAt FROM expenses e LEFT JOIN users u ON e.registered_by = u.id LEFT JOIN employees emp ON u.id = emp.id
AND e.description LIKE CONCAT('%', #{keyword}, '%')
AND e.expense_type = #{category}
ORDER BY e.created_at DESC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*) FROM expenses e


        AND e.description LIKE CONCAT('%', #{keyword}, '%')


        AND e.expense_type = #{category}

SELECT p.id, p.employee_id AS employeeId, p.pay_year AS payYear, p.pay_month AS payMonth, p.work_hours AS workHours, p.base_pay AS basePay, p.deduction, p.net_pay AS netPay, p.paid_at AS paidAt, p.note, p.created_at AS createdAt, e.name AS employeeName FROM payrolls p LEFT JOIN employees e ON p.employee_id = e.id
AND e.name LIKE CONCAT('%', #{keyword}, '%')
ORDER BY p.pay_year DESC, p.pay_month DESC, p.id DESC LIMIT #{size} OFFSET #{offset}

